27	\begin{theorem}
28	  \label{thm:rigidity_over_kbar}
29	  \lean{AlgebraicGeometry.rigidity_over_kbar}
30	  \leanok
31	  % SOURCE: Mumford, Abelian Varieties, Ch. II §4 (verbatim text not yet
32	  % retrieved — paywalled, no open copy in references/). No SOURCE QUOTE
33	  % is supplied: the source is not bundled and recalled text must not be
34	  % substituted (citation discipline).
35	  \textit{Source: Mumford, Abelian Varieties, II §4.}
36	  Let $\bar k$ be a field (in the use case, an algebraic closure of a base field $k$; the statement is intrinsic to $\bar k$ and does not require an ambient base $k$). Let $C : \mathrm{Over}\,(\Spec \bar k)$ be a smooth proper geometrically irreducible curve over $\bar k$ with $\genus(C) = 0$ (i.e.\ $\dim_{\bar k} H^1(C, \mathcal O_C) = 0$). Let $A : \mathrm{Over}\,(\Spec \bar k)$ be a smooth proper geometrically irreducible group scheme over $\bar k$, with identity element $\eta_A \in A(\bar k)$. Let
37	  \[
38	    f \colon C \longrightarrow A
39	  \]
40	  be a morphism of $\bar k$-schemes over $\Spec \bar k$, and let $p \in C(\bar k)$ be a $\bar k$-rational point such that $f(p) = \eta_A$. Then $f$ equals the constant morphism at $\eta_A$:
41	  \[
42	    f \;=\; \bigl(C \to \Spec \bar k \xrightarrow{\,\eta_A\,} A\bigr).
43	  \]
44	
45	  \emph{Encoding note (iter-126).} The Lean signature uses the abstract characterization $\mathtt{SmoothOfRelativeDimension}\ 1\ C.\mathtt{hom} + \mathtt{IsProper}\ C.\mathtt{hom} + \mathtt{GeometricallyIrreducible}\ C.\mathtt{hom} + \genus(C) = 0$ instead of a literal $\mathbb P^1_{\bar k}$ scheme. The two encodings are equivalent over $\bar k$ once the curve has a $\bar k$-rational point (Brauer--Severi triviality + Riemann--Roch on $C \cong \mathbb P^1_{\bar k}$); the abstract form is used because Mathlib snapshot \texttt{b80f227} does not ship a packaged $\mathtt{ProjectiveSpace}\,n\,S$ as a $\mathtt{Scheme.Over}\,S$, and the C.2.b–C.2.d proof decomposition below works for any smooth proper geometrically integral genus-0 curve over $\bar k$ without explicit $\mathbb P^1$ API.
46	\end{theorem}
47	
48	\begin{remark}
49	  \label{rem:rigidity_over_kbar_dim_dichotomy}
50	  \uses{thm:rigidity_over_kbar}
51	  The conclusion is vacuously true when $A$ is zero-dimensional: in that case $A = \Spec \bar k$ and every morphism $\mathbb P^1_{\bar k} \to A$ factors through $\Spec \bar k$ trivially. The substantive content of the theorem is the positive-dimensional case, which decomposes into the steps of \cref{sec:RigidityKbar_proof_decomposition}.
52	\end{remark}
53	
54	\section{Proof decomposition}
55	\label{sec:RigidityKbar_proof_decomposition}
56	
57	The proof of \cref{thm:rigidity_over_kbar} decomposes as follows. We reuse the sub-step labelling of Jacobian.tex \S C.2 so cross-references between the two chapters remain unambiguous.
58	
59	\begin{itemize}
60	  \item[\textbf{(C.2.b)}] \emph{Reduction to the project's rigidity lemma.} Let $c \colon \mathbb P^1_{\bar k} \to A$ denote the constant morphism at $\eta_A$. The conclusion $f = c$ follows from \cref{thm:GrpObj_eq_of_eqOnOpen} (i.e.\ \texttt{AlgebraicGeometry.Scheme.Over.ext\_of\_eqOnOpen}, after the iter-125 refactor) applied to $g_1 := f$, $g_2 := c$, $X := \mathbb P^1_{\bar k}$, $Y := A$, once we produce a non-empty open $U \subseteq \mathbb P^1_{\bar k}$ on which $U.\iota \circ f.\mathrm{left} = U.\iota \circ c.\mathrm{left}$ as scheme morphisms. We will take $U := \mathbb P^1_{\bar k}$. The refactored rigidity lemma's hypotheses are trivially satisfied: $\mathbb P^1_{\bar k}$ is smooth (hence reduced) and geometrically irreducible over $\bar k$, and $A$ is proper (hence separated) over $\bar k$.
61	
62	  \item[\textbf{(C.2.c)}] \emph{Image dimension argument.} The morphism $f$ goes from a proper geometrically integral $\bar k$-scheme of dimension $1$ to a smooth proper $\bar k$-scheme of dimension $g := \dim_{\bar k} A$. The set-theoretic image $f(\mathbb P^1_{\bar k}) \subseteq A$ is an irreducible closed subset of $A$ (continuous image of an irreducible space under a proper map). Dichotomy:
63	  \begin{itemize}
64	    \item If $g = 0$: $A = \Spec \bar k$ and the conclusion is vacuous (\cref{rem:rigidity_over_kbar_dim_dichotomy}).
65	    \item If $g \geq 1$ and the image is a single point: the image must be $\{\eta_A\}$ (the pointed hypothesis $f(p) = \eta_A$ pins it). Then $f$ is constant on underlying topological points, and the conclusion follows by promoting set-level equality to scheme-morphism equality (sub-step C.2.e of Jacobian.tex, applied via \cref{thm:GrpObj_eq_of_eqOnOpen}).
66	    \item If $g \geq 1$ and the image is one-dimensional: the image is an irreducible rational curve in $A$. This case is ruled out by the keystone classical input (C.2.d below).
67	  \end{itemize}
68	
69	  \item[\textbf{(C.2.d)}] \emph{Keystone: proper rational curves on an abelian variety are constant.} The remaining case --- the image of $f$ has dimension exactly $1$ --- is ruled out by Mumford's classical fact stated in the chapter introduction. Two standard proofs are sketched in Jacobian.tex \S C.2.d (the dual-abelian-variety route via $\Pic^0(\mathbb P^1_{\bar k}) = 0$, and the cotangent-bundle route via triviality of $\Omega_{A/\bar k}$). Both routes require Mathlib infrastructure not currently present (see \cref{sec:RigidityKbar_shared_pile}).
70	
71	  \item[\textbf{(C.2.e)}] \emph{Promotion of set-level equality to scheme-morphism equality.} Standard reduced-source / separated-target argument, integrated into the application of \cref{thm:GrpObj_eq_of_eqOnOpen} in C.2.b.
72	\end{itemize}
73	
74	\section{The shared cotangent-vanishing Mathlib pile}
75	\label{sec:RigidityKbar_shared_pile}
76	
77	The C.2.d keystone above (\emph{morphisms from $\mathbb P^1_{\bar k}$ to a positive-dimensional abelian variety over $\bar k$ are constant}) and the genus-$0$ identification alternative of \cref{thm:nonempty_jacobianWitness} (M2.d-alt of STRATEGY.md, which sidesteps Riemann--Roch by running the cotangent-vanishing argument directly) depend on the same Mathlib pile. STRATEGY.md \S M2.d-alt names this the \emph{shared cotangent-vanishing pile}. The iter-126 mathlib-analogist consult (\texttt{analogies/cotangent-vanishing-pile.md}) decomposed the pile into the four pieces below, revised the per-piece LOC budgets upward where the directive had under-scoped, and made the characteristic-$p$ option pick:
78	
79	\begin{itemize}
80	  \item[(i)] \emph{Group-scheme cotangent triviality.} The relative cotangent presheaf $\Omega_{G/k}$ of a smooth proper geometrically irreducible group scheme $G$ over a base field $k$ (no algebraic-closure hypothesis, per the iter-127 over-k commitment) is free of rank $\dim G$. Per the iter-126 analogist's naming-idiom alignment (Mathlib snapshot \texttt{b80f227} has \emph{no} \texttt{AbelianVariety} file; the \texttt{GrpObj} namespace per Yang+Merten 2026 is the canonical home), target names are \texttt{AlgebraicGeometry.GrpObj.omega\_free} and \texttt{AlgebraicGeometry.GrpObj.omega\_rank\_eq\_dim}. A prover-ready three-step sub-lemma decomposition (i.a)\,$\to$\,(i.b)\,$\to$\,(i.c) for the iter-128+ build lane is given in \cref{subsec:RigidityKbar_piece_i_decomposition}. Estimated build: \textbf{800--1500 LOC} (iter-126 analogist's correction over an earlier 200--400 LOC framing; the triviality is the chain Lie-algebra-of-\texttt{GrpObj} + shear-iso globalisation + relative-cotangent-presheaf trivialisation on top of the project's existing \texttt{relativeDifferentialsPresheaf}, inheriting the presheaf-vs-sheaf bridge cost from \texttt{analogies/cotangent-presheaf-design.md}).
81	
82	  \item[(ii)] \emph{Scheme-level $\mathrm d f = 0$ implies $f$ factors through $\Spec k$.} The companion algebraic fact: if a morphism $f \colon X \to Y$ between smooth proper $k$-schemes has $\mathrm d f \colon f^* \Omega_{Y/k} \to \Omega_{X/k}$ the zero map (e.g.\ because $\Omega_{Y/k}$ is trivial and $H^0(X, \Omega_{X/k}) = 0$), then $f$ factors through the constant morphism. In characteristic $0$ this is the standard differential-vanishing-implies-constancy argument. In characteristic $p > 0$ it requires the Frobenius iteration of piece (iii). Per the analogist's recommendation: the ring-level half aligns with Mathlib's \texttt{Differential.ContainConstants} typeclass (\texttt{Mathlib.RingTheory.Derivation.DifferentialRing}, lines 62--70; one Mathlib consumer at \texttt{FieldTheory.Differential.Liouville}); the scheme-level half is a NEEDS\_MATHLIB\_GAP\_FILL gap and the canonical name is \texttt{AlgebraicGeometry.Scheme.Over.ext\_of\_diff\_zero} (following the iter-125-refactored \texttt{ext\_of\_eqOnOpen} idiom). Estimated build: \textbf{250--500 LOC}.
83	
84	  \item[(iii)] \emph{Characteristic-$p$ handling --- \textbf{committed Option A: Frobenius iteration}.} Per the analogist's decisive pick (\texttt{analogies/cotangent-vanishing-pile.md} \S "Option A wins"): the three options on the table are
85	  \begin{itemize}
86	    \item Frobenius iteration (replace $f$ with $f \circ F^n$ for the $n$-th iterate of Frobenius; descent of the conclusion uses smoothness of $A$);
87	    \item Mumford's argument (Mumford, \emph{Abelian Varieties}, Chapter~II~\S4: abelian varieties contain no rational curves in characteristic $p$);
88	    \item Lifting to characteristic $0$ via Witt vectors.
89	  \end{itemize}
90	  Options B (Mumford) and C (Witt) each carry standalone multi-thousand-LOC dependencies (Mumford requires the very Pic$^0$ / cotangent machinery the project is trying to streamline; Witt-vector lifting requires a scheme-level Witt functor + smooth deformation + descent that Mathlib entirely lacks). Option A consumes Mathlib's first-class ring-level \texttt{frobenius} / \texttt{iterateFrobenius} from \texttt{Mathlib.Algebra.CharP.Frobenius} (lines 30--110+) and aligns with the project's existing scheme-level Frobenius design context (\texttt{AlgebraicJacobian/Rigidity.lean:48--55}); the scheme-level Frobenius lift remains a NEEDS\_MATHLIB\_GAP\_FILL gap, but Option A's net cost is dominated by adapting the ring-level idiom upward to schemes. Estimated build: \textbf{300--600 LOC}.

1	\chapter{The Abel--Jacobi map}
2	\label{chap:AbelJacobi}
3	
4	Let $C$ be a smooth proper curve over $k$ as in Chapter~\ref{chap:Genus}, and let $\Jac(C)$ be its Jacobian (Definition~\ref{def:Jacobian}). The constructions of this chapter consume only the Albanese universal property of $\Jac(C)$, as packaged by Definition~\ref{def:IsAlbanese} and provided uniformly in the marked point by Theorem~\ref{thm:nonempty_jacobianWitness}. The Lean formalisation closes every block in this chapter by a single projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$; the corresponding classical line-bundle / Pic-scheme description is recorded as a remark for each block.
5	
6	\section{Definition}
7	
8	\begin{definition}\leanok
9	[Abel--Jacobi map]
10	  \label{def:ofCurve}
11	  \lean{AlgebraicGeometry.Jacobian.ofCurve}
12	  \uses{def:Jacobian, def:IsAlbanese, thm:nonempty_jacobianWitness}
13	  Let $P \colon \Spec k \to C$ be a $k$-rational point of $C$, equivalently a morphism $P \colon \mathbf 1 \to C$ in the category of $k$-schemes over $\Spec k$. By Theorem~\ref{thm:nonempty_jacobianWitness} the Jacobian $\Jac(C)$ of Definition~\ref{def:Jacobian} carries, for each such marked point $P$, an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}. The \emph{Abel--Jacobi map at $P$} is the universal pointed morphism $\iota_P$ supplied by that Albanese structure:
14	  \[
15	    \alpha_P \;:=\; \iota_P \;\colon\; C \;\longrightarrow\; \Jac(C).
16	  \]
17	  Equivalently, $\alpha_P$ is the projection of the universal-pointed-morphism field of the Albanese predicate $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, evaluated at the marked point $P$.
18	\end{definition}
19	
20	\begin{remark}
21	[Classical description (Pic-scheme route)]
22	  \label{rem:ofCurve_classical}
23	  \uses{def:ofCurve, thm:nonempty_jacobianWitness}
24	  Classically (cf.\ Hartshorne~III.4 and FGA Explained, Chapter~9), the Abel--Jacobi map at $P$ admits the line-bundle description
25	  \[
26	    \alpha_P \colon C \;\longrightarrow\; \Pic^0_{C/k},\qquad Q \;\longmapsto\; [\mathcal O_C(Q - P)].
27	  \]
28	  Functorially, it is the morphism in the category of $k$-schemes induced by the line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ on $C \times C$ via the universal property of $\Pic^0_{C/k}$ as the moduli space of degree-$0$ line bundles on $C$. The Lean formalisation does not follow this route: the Pic-scheme representability machinery (Route~A of the proof of Theorem~\ref{thm:nonempty_jacobianWitness}, in particular sub-step~A.2) is not currently available in Mathlib. See Layer~I of Chapter~\ref{chap:Jacobian} for the formalisation route actually taken.
29	\end{remark}
30	
31	\section{Pointed property}
32	
33	\begin{lemma}\leanok
34	[$\alpha_P$ sends $P$ to $0$]
35	  \label{lem:comp_ofCurve}
36	  \lean{AlgebraicGeometry.Jacobian.comp_ofCurve}
37	  \uses{def:ofCurve, def:IsAlbanese}
38	  $P \;\circ\; \alpha_P \;=\; \eta[\Jac(C)]$, where $\eta[\Jac(C)]$ is the identity element of the group scheme $\Jac(C)$.
39	\end{lemma}
40	
41	\begin{proof}
42	  \uses{def:ofCurve, def:IsAlbanese, thm:nonempty_jacobianWitness}
43	  \leanok
44	  The Lean closure is the field projection from the Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ supplied by Theorem~\ref{thm:nonempty_jacobianWitness}. By Definition~\ref{def:IsAlbanese}, this predicate carries among its data the assertion $P \circ \iota_P = \eta_{\Jac(C)}$ that the universal pointed morphism sends the marked point to the identity of the target group scheme. Since $\alpha_P := \iota_P$ by Definition~\ref{def:ofCurve}, the claim is precisely the pointed-property field of that Albanese structure.
45	\end{proof}
46	
47	\begin{remark}
48	[Classical description]
49	  \label{rem:comp_ofCurve_classical}
50	  \uses{def:ofCurve, lem:comp_ofCurve, rem:ofCurve_classical}
51	  Under the classical Pic-scheme description of Remark~\ref{rem:ofCurve_classical}, the same equality reads at the level of $k$-points as
52	  \[
53	    \alpha_P(P) \;=\; [\mathcal O_C(P - P)] \;=\; [\mathcal O_C] \;=\; 0 \in \Pic^0_{C/k}(k),
54	  \]
55	  and globally as the statement that restricting the universal line bundle $\mathcal O_{C \times C}(\Delta - p_1^* P)$ along the section $(P, \mathrm{id}) \colon C \to C \times C$ gives the trivial line bundle on $C$, hence the zero point of $\Pic^0_{C/k}$. This classical content is not used in the Lean formalisation.
56	\end{remark}
57	
58	\section{Universal (Albanese) property}
59	
60	\begin{theorem}\leanok
61	[Albanese property of the Jacobian]
62	  \label{thm:exists_unique_ofCurve_comp}
63	  \lean{AlgebraicGeometry.Jacobian.exists_unique_ofCurve_comp}
64	  \uses{def:ofCurve, lem:comp_ofCurve, def:IsAlbanese}
65	  Let $A$ be an abelian variety over $k$ --- i.e.\ a smooth proper geometrically irreducible group scheme over $k$. For every pointed morphism $f \colon C \to A$ with $f \circ P = \eta[A]$, there exists a unique group-scheme morphism $g \colon \Jac(C) \to A$ such that $f = \alpha_P \circ g$.
66	  \[
67	  \begin{array}{ccc}
68	    C & \stackrel{f}{\longrightarrow} & A \\
69	    {\scriptstyle\alpha_P} \downarrow & \nearrow {\scriptstyle\exists ! g} & \\
70	    \Jac(C) & &
71	  \end{array}
72	  \]
73	\end{theorem}
74	
75	\begin{proof}
76	  \uses{def:IsAlbanese, thm:nonempty_jacobianWitness, def:ofCurve, lem:comp_ofCurve}
77	  \leanok
78	  The argument has two stages: the Lean closure (a direct projection from an Albanese witness) and the classical description (a Pic-scheme / rigidity argument that the Lean side does not replay).
79	
80	  \emph{Lean closure.} By Theorem~\ref{thm:nonempty_jacobianWitness}, the Jacobian $\Jac(C)$ is, uniformly in the marked point $P$, the underlying scheme of an Albanese witness for the pointed curve $(C, P)$: it carries an Albanese structure $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$ in the sense of Definition~\ref{def:IsAlbanese}, whose universal pointed morphism is the Abel--Jacobi map $\alpha_P$ of Definition~\ref{def:ofCurve} (with $\alpha_P \circ P = \eta_{\Jac(C)}$ being Lemma~\ref{lem:comp_ofCurve}). The universal-property data carried by this Albanese structure is, by Definition~\ref{def:IsAlbanese}, exactly the existence-and-uniqueness assertion of the theorem: for every $f \colon C \to A$ with $f \circ P = \eta_A$, there is a unique $g \colon \Jac(C) \to A$ with $f = \alpha_P \circ g$. The Lean side closes the goal by projecting this universal-property field of the Albanese witness $\mathrm{IsAlbanese}\,C\,P\,\Jac(C)$, applied to the data $(f, hf)$.
81	
82	  \emph{Classical description.} The classical proof of the same statement proceeds in two parts. In positive genus ($g(C) > 0$), the existence and uniqueness of the factorisation come from the Pic-scheme representability theorem together with the Stein factorisation of the Abel--Jacobi morphism: see Theorem~\ref{thm:nonempty_jacobianWitness}, Route~A (sub-steps A.1--A.4) for the line-bundle / universal-property route via $\Pic^0_{C/k}$, and Route~B (sub-steps B.1--B.3) for the symmetric-power / Stein-factorisation route. In genus $0$, the same statement reduces to the rigidity theorem for $C \to A$ established \emph{directly over $k$} --- the named declaration \cref{thm:rigidity_over_kbar} of \cref{chap:RigidityKbar}, whose signature is $k$-agnostic per the iter-127 over-k commitment (\texttt{analogies/cotangent-vanishing-pile-over-k.md}) and which is built out of the shared cotangent-vanishing pile pieces (i)+(ii)+(iii) over an arbitrary base field with no algebraic-closure, perfect-base, or Galois-descent hypothesis. See Theorem~\ref{thm:nonempty_jacobianWitness}, sub-cases C.1--C.3, in particular the seven-step expansion C.2.a--C.2.g, where sub-step C.2.f (Galois descent of morphism equality back to $k$) is \textbf{DROPPED} under the iter-127 commitment: no base-change-and-descent step appears anywhere in the M2 critical path. The protected signature of Theorem~\ref{thm:nonempty_jacobianWitness} does \emph{not} assume $C(k) \neq \emptyset$, so the genus-$0$ argument branches on whether a $k$-rational point exists. When $C(k) \neq \emptyset$, the supplied $P \in C(k)$ feeds the pointing hypothesis of \cref{thm:rigidity_over_kbar} directly --- no $C \cong \mathbb P^1_k$ identification is required, sidestepping the Brauer--Severi obstruction (Brauer--Severi conics over $\mathbb Q$ are the standard counterexample to an unconditional $k$-side identification). When $C(k) = \emptyset$, the $\mathtt{isAlbaneseFor}$ field of the genus-$0$ witness (\cref{def:genusZeroWitness}) is vacuously true at the Lean type level: the universal quantifier $\forall\, (P \colon \mathbf{1} \to C)$ ranges over the empty type. None of this classical content is replayed in the Lean formalisation: it is bundled into the deferred existence hypothesis Theorem~\ref{thm:nonempty_jacobianWitness}, whose proof is the project's single explicit foundational gap.
83	\end{proof}
84	
85	\section{Implementation route via the Albanese framework}
86	
87	The three results above are formalised through the Albanese framework of Chapter~\ref{chap:Jacobian}. In the absence of Mathlib's Pic-scheme machinery, the Jacobian is defined (Layer~I) as the underlying scheme of an Albanese witness uniform in the marked point (Theorem~\ref{thm:nonempty_jacobianWitness}); the universal-property data $(\iota_P,\, \text{factorisation})$ is then carried by the Albanese predicate (Definition~\ref{def:IsAlbanese}) and projects directly into the three results of this chapter (Layer~II): the Abel--Jacobi map $\alpha_P := \iota_P$ of Definition~\ref{def:ofCurve}, its pointed property of Lemma~\ref{lem:comp_ofCurve}, and the universal factorisation of Theorem~\ref{thm:exists_unique_ofCurve_comp}. Existence of a uniform-over-$P$ Albanese object is the single remaining mathematical hypothesis pending the formalisation of either Pic-scheme representability (Route~A), symmetric-power quotients plus Stein factorisation (Route~B), or rigidity for $C \to A$ established \emph{directly over $k$} (genus-$0$ sub-case, via \cref{thm:rigidity_over_kbar} per the iter-127 over-k commitment; no base-change to $\bar k$ and no Galois descent of morphism equality enter, and sub-step C.2.f of \S~C.2 is correspondingly DROPPED).
88	
89	The classical proof via line bundles --- using the universal property of $\Pic^0_{C/k}$, dual abelian varieties, and (for the genus-$0$ sub-case) rigidity for $C \to A$ established directly over $k$ via \cref{thm:rigidity_over_kbar} (per the iter-127 over-k commitment; no base-change to $\bar k$ and no Galois descent of morphism equality enter) --- gives the same conclusions but requires more Mathlib infrastructure than is presently available, as catalogued in the proof of Theorem~\ref{thm:nonempty_jacobianWitness} and the milestone roadmap of \texttt{STRATEGY.md}. The Albanese-framework route used here is mathematically equivalent and bundles all of the missing infrastructure into that single deferred existence hypothesis.
90

1	\chapter{Sheaf condition along the structure-sheaf forget composite}
2	\label{chap:Cohomology_SheafCompose}
3	
4	This chapter records the first step of Phase~A: equipping the abstract sheaf-cohomology pipeline with the link it needs to compute $H^1(C, \mathcal O_C)$ as an abelian group. It is the smallest unblocking unit of progress toward the genus of a smooth proper curve (Definition~\ref{def:genus}).
5	
6	The chapter introduces no protected declarations: every definition and lemma here is auxiliary, supporting the construction of $H^1(C, \mathcal O_C)$ in subsequent Phase~A iterations.
7	
8	\section{Statement}
9	
10	The structure sheaf $\mathcal O_C$ of a scheme is delivered as a sheaf of commutative rings. To plug it into the cohomology API, which is formulated for sheaves of abelian groups, one must first transport the sheaf condition along the forgetful composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$. The following theorem packages exactly this transport.
11	
12	\begin{theorem}\leanok
13	[Sheaf condition transports along the structure-sheaf forget composite]
14	  \label{thm:HasSheafCompose_forget}
15	  \lean{AlgebraicGeometry.Cohomology.instHasSheafCompose_forget_CommRing_AddCommGrp}
16	  Let $X$ be a topological space. Then the Grothendieck topology of opens of $X$ transports sheaves along the forgetful composite from commutative rings to abelian groups.
17	\end{theorem}
18	
19	\begin{proof}
20	
21	
22	\leanok
23	  Both forgetful functors in the composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$ create (in particular preserve) all small limits. The sheaf condition for the topology of opens is expressed as preservation of certain multiequalizer limits. Composing two limit-preserving functors gives a limit-preserving functor, so post-composition with the forget composite preserves the sheaf condition.
24	\end{proof}
25	
26	\section{Use in the project}
27	
28	Theorem~\ref{thm:HasSheafCompose_forget} is the gateway to:
29	\begin{itemize}
30	  \item constructing $\mathcal O_C$ as a sheaf of abelian groups on $C$;
31	  \item plugging that sheaf into the abstract cohomology functor once sheafification and $\Ext$ are available (Phase~A steps 2--3);
32	  \item endowing the resulting $H^1$ with a $k$-vector-space structure via the $k$-algebra structure on $\Gamma(C, \mathcal O_C)$ (Phase~A step~4);
33	  \item finite-dimensionality via Serre's theorem on coherent cohomology of proper $k$-schemes (Phase~A step~5).
34	\end{itemize}
35	
36	The chain is: sheaf-compose transport (this chapter) $\to$ sheafification $\to$ $\Ext$ $\to$ $k$-module structure on $H^1$ $\to$ Serre finiteness $\to$ genus.
37	
38	\begin{remark}[Lean implementation]
39	  In Lean the forget composite is written as the concatenation of the two structure-forgetful functors $\mathrm{CommRingCat} \to \mathrm{RingCat} \to \mathrm{AddCommGrpCat}$. The proof appeals to the general fact that a functor preserving limits of a given size preserves the sheaf condition when post-composed with a presheaf. The instance body is a 5-line composition of Mathlib's limit-preservation lemmas.
40	\end{remark}
41

1	\chapter{Structure sheaf as a sheaf of abelian groups, sheafification and Ext}
2	\label{chap:Cohomology_StructureSheafAb}
3	
4	This chapter executes Phase~A steps~2--4 on the topology of opens of an arbitrary topological space, using the sheaf-compose instance of Chapter~\ref{chap:Cohomology_SheafCompose} as input. It supplies three pieces of infrastructure that sit immediately upstream of the genus definition (Definition~\ref{def:genus}):
5	
6	\begin{enumerate}
7	  \item Sheafification for abelian-group-valued sheaves on opens (Phase~A step~2).
8	  \item $\Ext$ on the same sheaf category (Phase~A step~3).
9	  \item Promotion of the structure sheaf $\mathcal O_C$ from commutative-ring-valued to abelian-group-valued, packaging the data on which sheaf cohomology can be evaluated (Phase~A step~4 first half).
10	\end{enumerate}
11	
12	No new mathematical content is introduced here, only the typeclass plumbing and one definition. After this chapter lands, the only remaining steps in Phase~A are equipping $H^1(C, \mathcal O_C)$ with a $k$-vector-space structure and proving Serre finiteness; both are deferred to subsequent iterations.
13	
14	The chapter introduces no protected declarations: every definition and instance here is auxiliary, supporting the construction of $H^1(C, \mathcal O_C)$ in Definition~\ref{def:genus}.
15	
16	\section{Sheafification of abelian-group-valued sheaves on opens}
17	
18	\begin{theorem}\leanok
19	[Sheafification on the topology of opens, abelian-group valued]
20	  \label{thm:HasSheafify_Opens_AddCommGrp}
21	  \lean{AlgebraicGeometry.Cohomology.instHasSheafify_Opens_AddCommGrp}
22	  Let $X$ be a topological space. Then the Grothendieck topology of opens of $X$ admits sheafification for sheaves valued in the category of abelian groups.
23	\end{theorem}
24	
25	\begin{proof}
26	
27	
28	\leanok
29	  Mathlib's general sheafification API constructs sheafification whenever weak sheafification holds and the resulting sheafification preserves finite limits. For the topology of opens of $X$ and the category of abelian groups, both prerequisites are already available in Mathlib (concrete-category sheafification on a small site, plus exactness of abelian-group-valued sheafification). The instance is therefore inferable; the formal task is to establish the universe pinning needed to make instance synthesis succeed.
30	\end{proof}
31	
32	\section{$\Ext$ for sheaves on opens}
33	
34	\begin{theorem}\leanok
35	[$\Ext$ on the topology of opens, abelian-group valued]
36	  \label{thm:HasExt_Sheaf_Opens_AddCommGrp}
37	  \lean{AlgebraicGeometry.Cohomology.instHasExt_Sheaf_Opens_AddCommGrp}
38	  \uses{thm:HasSheafify_Opens_AddCommGrp}
39	  Let $X$ be a topological space. Then the category of sheaves of abelian groups on the topology of opens of $X$ admits $\Ext$ groups.
40	\end{theorem}
41	
42	\begin{proof}
43	
44	
45	\leanok
46	  The category of abelian groups is abelian. The sheaf category inherits an abelian structure from an abelian value category once sheafification is available (Theorem~\ref{thm:HasSheafify_Opens_AddCommGrp}). Mathlib's standard construction produces $\Ext$ from any abelian category.
47	\end{proof}
48	
49	\section{Structure sheaf as a sheaf of abelian groups}
50	
51	\begin{definition}\leanok
52	[Structure sheaf as a sheaf of abelian groups]
53	  \label{def:Scheme_toAbSheaf}
54	  \lean{AlgebraicGeometry.Scheme.toAbSheaf}
55	  \uses{thm:HasSheafCompose_forget}
56	  Let $C$ be a scheme. The structure sheaf of $C$, viewed as a sheaf of abelian groups on the topology of opens of the underlying topological space of $C$, is obtained by post-composing the commutative-ring-valued structure sheaf with the forgetful composite $\mathrm{CommRing} \to \mathrm{Ring} \to \mathrm{Ab}$ of Chapter~\ref{chap:Cohomology_SheafCompose}.
57	\end{definition}
58	
59	The construction uses the sheaf-compose functoriality, which requires the sheaf-compose instance from Chapter~\ref{chap:Cohomology_SheafCompose}. Functoriality in $C$ is delegated to a future iteration once it is needed for naturality of the cohomology long exact sequence.
60	
61	\section{Use in the project}
62	
63	The chain $\text{sheaf-compose} \to \text{sheafification} \to \Ext \to \text{toAbSheaf}$ unblocks the abelian-group-level definition of $H^n(C, \mathcal O_C)$:
64	\[
65	  H^n(C, \mathcal O_C) \;:=\; \text{toAbSheaf}(C).H\,n,
66	\]
67	where $H$ is the abstract sheaf-cohomology functor. The result is automatically an abelian group. Only two steps remain inside Phase~A:
68	
69	\begin{itemize}
70	  \item Equip $H^1(C, \mathcal O_C)$ with the $k$-module structure inherited from the $k$-algebra structure on $\Gamma(C, \mathcal O_C)$ (Phase~A step~5).
71	  \item Establish finite rank via Serre's theorem on coherent cohomology of proper $k$-schemes (Phase~A step~6).
72	\end{itemize}
73	
74	Both are deferred to iterations beyond this chapter.
75	
76	\begin{remark}[Lean implementation]
77	  The sheafification and $\Ext$ instances are inferable from Mathlib's small-site and concrete-category APIs. The structure-sheaf promotion uses Mathlib's sheaf-compose machinery together with the forget-composite instance of Chapter~\ref{chap:Cohomology_SheafCompose}. The only work is universe annotation: the morphism universe of the sheaf category lives one level above the object universe, and the instances must be pinned accordingly.
78	\end{remark}
