import re, glob, os
labels=set(); refs={}
files=glob.glob("*.tex")
for f in files:
    s=open(f).read()
    for m in re.findall(r'\\label\{([^}]+)\}', s):
        labels.add(m)
for f in files:
    s=open(f).read()
    # strip comment lines for ref extraction
    lines=[ln.split('%')[0] if not ln.lstrip().startswith('%') else '' for ln in s.splitlines()]
    body="\n".join(lines)
    for cmd in ['uses','cref','Cref','ref','proves']:
        for m in re.findall(r'\\'+cmd+r'\{([^}]+)\}', body):
            for part in m.split(','):
                part=part.strip()
                if part:
                    refs.setdefault(part,set()).add(f)
missing=sorted(set(refs)-labels)
print("TOTAL labels:",len(labels))
print("MISSING ref targets (referenced but no \\label):")
for r in missing:
    print("  ",r,"  <-",sorted(refs[r]))
